-- Record 1 from AppSettings
  -- Insert record
  INSERT INTO "public"."app_settings" ("id", "created_at", "updated_at", "created_by_id", "created_by", "is_sample", "slug", "payload", "description") VALUES ('6974df315463aeba1cb32baa', '2026-01-24T15:03:13.131000', '2026-02-09T17:44:14.243000', '68f767a3d5fce1486d4cf557', '911smartfix@gmail.com', false, 'business-branding', '{"logo_url": "", "store_name": "", "terms_sales": "", "terms_workorders": "", "warranty_sales": {"text": "📄 TÉRMINOS Y CONDICIONES DE GARANTÍA – VENTAS\n911 SmartFix | Avenida Andalucía, San Juan\n🛡️ GARANTÍA DE PRODUCTOS\nTodos los productos vendidos por 911 SmartFix están cubiertos por una garantía limitada según su categoría:\n1. Accesorios Nuevos (cargadores, cables, estuches, protectores, etc.)\nGarantía de 15 días por defecto de fabricación.\nNo cubre mal uso, daños por agua, caídas, ni desgaste normal.\n2. Equipos Reacondicionados o Usados (celulares, consolas, tablets, laptops, etc.)\nGarantía de 30 días en funcionamiento interno (pantalla, batería, placa base).\nNo incluye roturas físicas, humedad, caídas o intentos de manipulación por terceros.\nSi el equipo tiene iCloud o bloqueo de cuenta y el cliente no lo remueve, la garantía queda anulada.\n3. Consolas o Electrónicos Especiales (Nintendo, PlayStation, etc.)\nGarantía de 30 días por fallo interno no causado por mal manejo.\nNo se cubren errores por golpes, sobrecalentamiento por mal uso, ni daños en puertos externos (HDMI, USB, etc.) si no fueron notificados al momento de la venta.\n❗EXCLUSIONES GENERALES\nNo se aceptan devoluciones en efectivo.\nCambios de producto solo aplican si el mismo presenta defecto de fábrica dentro del periodo establecido.\nLa garantía queda inválida si el producto presenta signos de mal uso o intento de reparación ajena.\n📌 PROCESO PARA RECLAMOS\nPresentar el recibo o evidencia de compra.\nEl producto debe ser evaluado por nuestro técnico.\nSi aplica garantía, se reemplaza o repara según disponibilidad.\nEl proceso puede tomar entre 24 a 72 horas laborables.\n✅ Al realizar su compra, el cliente acepta estos términos y condiciones.", "duration": "5"}}'::jsonb, 'Logo y términos del negocio') ON CONFLICT DO NOTHING;
