-- Record 11 from EmailTemplate
  -- Insert record
  INSERT INTO "public"."email_template" ("id", "created_at", "updated_at", "created_by_id", "created_by", "is_sample", "custom_warranty", "logo_url", "review_link", "main_message", "enabled", "next_steps_items", "send_to", "event_type", "show_review_request", "custom_whatsapp", "alert_title", "custom_sections", "show_checklist", "show_next_steps", "show_phone_contact", "show_warranty", "show_whatsapp_contact", "header_title", "show_photos", "alert_message", "warranty_type", "is_default", "custom_hours", "show_hours", "name", "custom_phone", "header_subtitle") VALUES ('698a4ef5b97ebbe7cbec06de', '2026-02-09T21:17:41.742000', '2026-02-10T16:38:31.890000', '68f767a3d5fce1486d4cf557', '911smartfix@gmail.com', false, 'Términos y Condiciones – 911 SmartFix
Al dejar su equipo para diagnóstico o reparación, el cliente acepta los siguientes términos y condiciones:
Diagnóstico y autorización
Todo equipo será evaluado antes de realizar la reparación.
Ninguna reparación se realizará sin la autorización previa del cliente.
Reparaciones
Las reparaciones se realizan con piezas originales o de alta calidad, según lo acordado con el cliente.
El tiempo de reparación puede variar según la complejidad del trabajo y la disponibilidad de piezas.
Garantía
Las reparaciones incluyen garantía limitada sobre la pieza reemplazada y la mano de obra.
La garantía no cubre daños por golpes, caídas, humedad, líquidos, manipulación indebida o reparaciones realizadas por terceros después del servicio.
Equipos mojados o con daño severo
En equipos mojados o con daño interno avanzado, no se garantiza la recuperación total del equipo.
El cliente acepta el riesgo asociado a este tipo de reparaciones.
Datos y privacidad
El cliente es responsable de respaldar su información antes de la reparación.
911 SmartFix no se hace responsable por pérdida de datos.
Equipos no reclamados
Equipos no reclamados dentro de 30 días después de notificar que están listos podrán estar sujetos a cargos de almacenamiento o disposición del equipo.
Pagos
El pago debe realizarse al momento de retirar el equipo, a menos que se acuerde lo contrario.
Todos los precios son finales según lo cotizado.
Aceptación
Al dejar el equipo, el cliente confirma que ha leído y acepta estos términos y condiciones.', 'https://base44.app/api/apps/68f767a3d5fce1486d4cf555/files/public/68f767a3d5fce1486d4cf555/2db05f82c_ChatGPTImage4feb202610_03_37am.png', '', 'Te mantendremos informado en cada paso del proceso. Recibirás actualizaciones automáticas por email cuando haya cambios en el estado de tu orden.', true, '["Diagnóstico: Evaluaremos tu equipo en detalle", "Cotización: Te contactaremos con el costo y tiempo estimado", "Reparación: Una vez aprobado, comenzamos el trabajo", "Notificación: Te avisaremos cuando esté listo"]'::jsonb, 'customer', 'intake', false, '7873444995', 'Orden confirmada', '[]'::jsonb, true, true, true, true, true, '¡Orden Recibida!', true, 'Hemos recibido tu equipo y ya estamos trabajando en ello.', 'repairs', false, 'Lunes a Viernes 9:00AM-5:00PM', true, 'Orden Recibida', '7873444995', 'Tu equipo está en buenas manos') ON CONFLICT DO NOTHING;

