-- Sync migrated users with existing auth users
-- This matches migrated user records with auth.users by email/phone
-- and updates all foreign key references to use the auth user ID
DO $$
DECLARE
  migrated_user RECORD;
  auth_user_id UUID;
  sync_count INTEGER;
BEGIN
  FOR migrated_user IN
    SELECT id, email FROM public.users WHERE email IS NOT NULL AND email != ''
  LOOP
    auth_user_id := NULL;
    SELECT id INTO auth_user_id FROM auth.users WHERE email = migrated_user.email LIMIT 1;
    IF auth_user_id IS NOT NULL AND auth_user_id::text != migrated_user.id THEN
      SELECT sync_user_id_manual(auth_user_id, migrated_user.email, NULL) INTO sync_count;
      RAISE NOTICE 'Synced user % (email: %) with auth user %', migrated_user.id, migrated_user.email, auth_user_id;
    END IF;
  END LOOP;
END $$;

COMMIT;
